// Space: O(h)

/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
 * };
 */
class Solution {
public:
    vector<int> getAllElements(TreeNode* root1, TreeNode* root2) {
        vector<int> result;
        Iterator<TreeNode*> left(root1), right(root2);
        while (*left || *right) {
            if (!*right || ((*left) && (*left)->val < (*right)->val)) {
                result.emplace_back((*left)->val);
                ++left;
            } else {
                result.emplace_back((*right)->val);
                ++right;
            }
        }
        return result;
    }

private:
    template<typename T>
    class Iterator {
    public:
        Iterator(T root)
         : stack_{{root, false}}
         , curr_{} {
             ++(*this);
        }

        Iterator& operator++() {
            while (!stack_.empty()) {
                T root; bool is_visited;
                tie(root, is_visited) = stack_.back(); stack_.pop_back();
                if (!root) {
                    continue;
                }
                if (is_visited) {
                    curr_ = root;
                    return *this;
                }
                stack_.emplace_back(root->right, false);
                stack_.emplace_back(root, true);
                stack_.emplace_back(root->left, false);
            }
            curr_ = T{};
            return *this;
        }

        const T& operator*() const {
            return curr_;
        }

    private:
        vector<pair<T, bool>> stack_;
        T curr_;
    };
};

# Time:  O(n)
# Space: O(h)

# Definition for a binary tree node.
class TreeNode(object):
    def __init__(self, x):
        self.val = x
        self.left = None
        self.right = None


class Solution(object):
    def getAllElements(self, root1, root2):
        """
        :type root1: TreeNode
        :type root2: TreeNode
        :rtype: List[int]
        """
        def inorder_gen(root):
            result, stack = [], [(root, False)]
            while stack:
                root, is_visited = stack.pop()
                if root is None:
                    continue
                if is_visited:
                    yield root.val
                else:
                    stack.append((root.right, False))
                    stack.append((root, True))
                    stack.append((root.left, False))
            yield None

        result = []
        left_gen, right_gen = inorder_gen(root1), inorder_gen(root2)
        left, right = next(left_gen), next(right_gen)
        while left is not None or right is not None:
            if right is None or (left is not None and left < right):
                result.append(left)
                left = next(left_gen)
            else:
                result.append(right)
                right = next(right_gen)
        return result
